import { Menu } from '@headlessui/react'

export default function CategroyDropdown() {
  return (
    <Menu as="div" className="relative inline-block text-left">
      <Menu.Button className="bg-blue-600 text-white px-4 py-2 rounded">
        Options
      </Menu.Button>

      <Menu.Items className="absolute mt-2 w-40 bg-white shadow-lg rounded">
        <Menu.Item>
          {({ active }) => (
            <button className={`${active && 'bg-gray-100'} w-full text-left px-4 py-2`}>
              Profile
            </button>
          )}
        </Menu.Item>
      </Menu.Items>
    </Menu>
  )
}